CREATE TABLE IF NOT EXISTS users (id BIGSERIAL PRIMARY KEY, tg_id BIGINT UNIQUE, first_name VARCHAR(128) NOT NULL, last_name VARCHAR(128), username VARCHAR(64), photo_url TEXT, bio TEXT DEFAULT '', is_premium BOOLEAN DEFAULT FALSE, premium_until TIMESTAMP, stars_balance INTEGER DEFAULT 0, is_online BOOLEAN DEFAULT FALSE, last_seen TIMESTAMP DEFAULT NOW(), created_at TIMESTAMP DEFAULT NOW())